-              <ResourceDot leaked={false} label={withDone ? "Task cleanly exited" : "Background task running"} />
-            </div>
-          </div>
-        </div>
-      </div>
-
-      {/* Controls */}
-      <div className="mt-6 flex justify-center gap-3">
-        <button
-          onClick={play}
-          disabled={isPlaying}
